                                            <p>{answer.description}</p>
                                        </Fragment>)}
                                    </div>
                                </div>
                            </div>;
      } else {
        message = <div className="answer">
                                            <div className="answer-text">
                                                {this.state.message}
                                            </div>
                                </div>;
      }
      if (this.state.btn.checked) {
        result = <div>
