                                        <div className="download-button">
                                            {printbutton}
                                        </div>
                                    </div>;
      } else result = null;
      return <div className="answer-div">
                            {result}
                            <button className="add-button" onClick={this.handleClick} shown={this.state.btn.checked}>{this.state.btn.text}</button>
                        </div>;
    }}
            </Context.Consumer>;
}

